// =============================================================
// SSRF Check — block private IPs before HTTP Request
// =============================================================
// Uses regex parsing instead of new URL() (unavailable in n8n sandbox).
// =============================================================

const item = $input.first().json;
const { resolvedConfig } = item;
const url = resolvedConfig.url;

if (!url) {
  return {
    json: {
      ...item,
      stepResult: { success: false, error: 'Webhook step missing url in config' },
    }
  };
}

try {
  // Parse URL via regex (n8n sandbox lacks URL constructor)
  const urlMatch = url.match(/^(https?):\/\/([^/:]+)(:\d+)?(\/.*)?$/);
  if (!urlMatch) {
    return {
      json: {
        ...item,
        stepResult: { success: false, error: `Invalid webhook URL format: ${url}` },
      }
    };
  }

  const hostname = urlMatch[2].toLowerCase();

  const privatePatterns = [
    /^10\./,
    /^172\.(1[6-9]|2\d|3[01])\./,
    /^192\.168\./,
    /^127\./,
    /^localhost$/i,
    /^::1$/,
    /\.local$/,
    /^0\.0\.0\.0$/,
    /^169\.254\./,
  ];

  const isPrivate = privatePatterns.some(p => p.test(hostname));
  if (isPrivate) {
    return {
      json: {
        ...item,
        stepResult: { success: false, error: `Webhook URL targets private address: ${hostname}` },
      }
    };
  }

  return {
    json: {
      ...item,
      webhookUrl: url,
      webhookMethod: resolvedConfig.method || 'POST',
      webhookBody: resolvedConfig.body || '{}',
      ssrfPassed: true,
    }
  };
} catch (e) {
  return {
    json: {
      ...item,
      stepResult: { success: false, error: `Invalid webhook URL: ${url}` },
    }
  };
}

// =============================================================
// Save Input Payload — audit per attempt (T-209)
// =============================================================
// Save resolved URL + method + body BEFORE HTTP Request.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

const item = $input.first().json;
const inputPayload = {
  url: item.webhookUrl,
  method: item.webhookMethod,
  body: item.webhookBody,
};

if (item.currentStepExecId) {
  await supabaseRequest(
    `workflow_step_executions?id=eq.${item.currentStepExecId}`,
    'PATCH',
    { input_payload: inputPayload }
  );
}

return { json: item };

// Build success result from HTTP response — preserve orchestrator context
try {
  const item = $('SSRF Check').first().json;
  const httpResult = $('HTTP Request').first().json;
  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: {
          statusCode: httpResult.statusCode || 200,
          responseBody: typeof httpResult === 'string' ? httpResult : JSON.stringify(httpResult),
        },
      },
    }
  };
} catch (e) {
  const item = $('SSRF Check').first().json;
  return {
    json: {
      ...item,
      stepResult: { success: false, error: `Webhook failed: ${e.message}` },
    }
  };
}

// Pass through SSRF/error result — preserve orchestrator context
const item = $input.first().json;
return { json: { ...item } };
